function epsilonClosure(state, epsilonTransitions):
 closure = SET()
 stack = STACK()

 closure.add(state)
 stack.push(state)

 while stack is not empty:
 current = stack.pop()
 for each nextState in epsilonTransitions[current]:
 if nextState not in closure:
 closure.add(nextState)
 stack.push(nextState)

 return closure

